from sentence_transformers import SentenceTransformer, util

model = SentenceTransformer("paraphrase-multilingual-MiniLM-L12-v2")
kb = ["Cancel subscription in Billing", "Free trial 14 days"]
kb_embs = model.encode(kb, normalize_embeddings=True, convert_to_tensor=True)

def route(query, threshold_high=0.65, threshold_mid=0.40):
    q_emb = model.encode([query], normalize_embeddings=True, convert_to_tensor=True)
    scores = util.cos_sim(q_emb, kb_embs)[0]
    best_score = float(scores.max())
    best_doc = kb[scores.argmax()]
    if best_score >= threshold_high:
        return {"tier": "high", "doc": best_doc, "score": best_score}
    elif best_score >= threshold_mid:
        return {"tier": "mid", "doc": best_doc, "score": best_score}
    else:
        return {"tier": "low", "doc": best_doc, "score": best_score}

print(route("how do I cancel?")["tier"])        # high
print(route("¿Cómo cancelo?")["tier"])           # high
print(route("what's the weather?")["tier"])      # low

