import math

def mock_embed(text, dim=16):
    vec = [0.0] * dim
    for word in text.lower().split():
        idx = hash(word) % dim
        vec[idx] += 1.0
    norm = math.sqrt(sum(v * v for v in vec))
    if norm > 0:
        vec = [v / norm for v in vec]
    return vec

class ConfidenceRouter:
    HIGH_THRESHOLD = 0.7
    MID_THRESHOLD = 0.4

    def __init__(self, documents, embed_fn=mock_embed):
        self.documents = documents
        self.embed_fn = embed_fn
        self.doc_embeddings = [self.embed_fn(doc) for doc in documents]

    def _cosine_similarity(self, a, b):
        dot = sum(x * y for x, y in zip(a, b))
        na = math.sqrt(sum(x * x for x in a))
        nb = math.sqrt(sum(x * x for x in b))
        if na == 0 or nb == 0:
            return 0.0
        return dot / (na * nb)

    def search(self, query, top_k=3):
        q_emb = self.embed_fn(query)
        scored = [{"document": doc, "score": self._cosine_similarity(q_emb, emb)}
                  for doc, emb in zip(self.documents, self.doc_embeddings)]
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def route(self, query, top_k=3):
        results = self.search(query, top_k)
        best = results[0]["score"] if results else 0.0
        if best >= self.HIGH_THRESHOLD:
            return {"tier": "high", "action": "direct_answer", "results": results}
        elif best >= self.MID_THRESHOLD:
            return {"tier": "mid", "action": "rerank", "results": results}
        else:
            return {"tier": "low", "action": "fallback", "results": results}

